input.command:
$skillsSource = "$env:TEMP\anthropics-skills\skills"
$skillsDest = "$env:USERPROFILE\.claude\skills"

$results = @()
Get-ChildItem $skillsSource -Directory | ForEach-Object {
    $skillName = $_.Name
    $skillFile = Join-Path $_.FullName "SKILL.md"
    $destFile = Join-Path $skillsDest "$skillName.md"

    if (Test-Path $skillFile) {
        $existed = Test-Path $destFile
        Copy-Item $skillFile $destFile -Force
        $results += [PSCustomObject]@{ Skill = $skillName; Status = if ($existed) { "Updated" } else { "Installed" } }
    } else {
        $results += [PSCustomObject]@{ Skill = $skillName; Status = "No SKILL.md found" }
    }
}
$results | Format-Table -AutoSize
